import React, { Component } from 'react';
import Navitem from './Navitem';
import { saveAs } from 'file-saver';
import { Slide, Fade, Zoom } from 'react-slideshow-image';
import 'react-slideshow-image/dist/styles.css'


const projects = [
  {title: 'ROS Malware Dataset & Detection',
   subtitle: 'Co-Authored paper accepted to 2021 IEEE IRC',
   time: 'Summer 2021',
   image: '/robomal_yellow.jpg',
   link: 'https://purr.purdue.edu/publications/3860'},

   {title: 'Semantic Network of Kitchen IoT',
    subtitle: 'Bringing Intelligent User Assistance to the Smart Kitchen',
    time: 'Fall 2020',
    image: '/ble.png',
    link: '/research'},

    {title: 'EmoSwiper: Predict Emotion from Swipes',
     subtitle: 'Most Marketable Award at Smart Software Hackathon',
     time: 'Spring 2021',
     image: '/emoswiper.jpg',
     link: 'https://github.com/haozheee/EmoSwiper'},

     {title: 'Smartran: Transport with Estimated Covid Risk',
      subtitle: 'Third Place at SAE MobilityForward Challenge: AI Mini-Challenge',
      time: 'Fall 2021',
      image: '/sae.png',
      link: 'https://saemobilityforwardchallenge.com/'}
 ];

const properties = {
  autoplay: true,
  arrows: false
};

class SlideShow extends Component {
    constructor(props)
    {
        super(props);
        this.state = {
          'active_index': 0,
          'intervalId': null
        }
        this.slideRef = React.createRef();
    }


    back = () => {
      this.slideRef.current.goBack();
    }

    next = () => {
      this.slideRef.current.goNext();
    }


    render() {
        return (
            <div style={{"width":"100%", "overflow":"hidden"}}>
              <Fade className='slideshow_container' ref={this.slideRef} {...properties}>
                {projects.map((project_obj, index) => (
                  <div className='slideshow_item' >
                    <div className='slideshow_left'>
                      <a href={project_obj.link}>
                      <div className="slideshow_text"
                        key={this.state['active_index']}
                      >
                        <h4><a href={project_obj.link}> {project_obj.title} </a></h4>
                        <h5> {project_obj.subtitle} </h5>
                        <h5> {project_obj.time} </h5>
                        <div className='slideshow_text_empty'>  </div>
                      </div>
                      </a>
                      <div className="slideshow_control">
                        <div className="slideshow_control_icon">
                          <a href={'https://github.com/haozheee'} className="navitemlink">GitHub</a>
                        </div>
                        <div className="slideshow_control_icon">
                          <a href={'https://www.linkedin.com/in/haozhe-zhou-8b6882170/'} className="navitemlink">LinkedIn</a>
                        </div>
                        <div className="slideshow_control_icon">
                          <a href={'/CV_HAOZHEZHOU_1102.pdf'} className="navitemlink">Curriculum Vitae</a>
                        </div>
                        <div className="slideshow_control_button" onClick={this.next}>
                        →
                        </div>
                        <div className="slideshow_control_button" onClick={this.back}>
                        ←
                        </div>
                        <div className="slideshow_control_sep">
                        </div>
                      </div>
                    </div>
                    <a href={project_obj.link}>
                    <div className="slideshow_image"  style={{'background-image': `url(${project_obj.image})`,}}/>
                    </a>
                  </div>
                ))}
              </Fade>
            </div>
            )
        }
    }

    export default SlideShow
